"use client";

import Image from "next/image";
import { useTheme } from "next-themes";
import { useEffect, useState } from "react";
import { cn } from "@/lib/utils";

interface LogoProps {
  className?: string;
}

export const LogoIcon = ({ className }: LogoProps) => {
  const { theme, systemTheme } = useTheme();
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  if (!mounted) {
    return <span className={cn("size-6 animate-pulse bg-muted rounded-full inline-block", className)} />;
  }

  const currentTheme = theme === "system" ? systemTheme : theme;
  const src = currentTheme === "dark" 
    ? "/logo/freddy-logo-icon-light.png" 
    : "/logo/freddy-logo-icon-dark.png";

  return (
    <Image
      src={src}
      alt="Freddy UI Icon"
      width={65}
      height={65}
      style={{
        width: "auto",
        height: "auto",
      }}
      className={cn("size-6 object-contain", className)}
    />
  );
};

export const Logo = ({ className }: LogoProps) => {
  const { theme, systemTheme } = useTheme();
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  if (!mounted) {
    return <span className={cn("h-6 w-24 animate-pulse bg-muted rounded inline-block", className)} />;
  }

  const currentTheme = theme === "system" ? systemTheme : theme;
  const src = currentTheme === "dark" 
    ? "/logo/freddy-logo-light.png" 
    : "/logo/freddy-logo-dark.png";

  return (
    <Image
      src={src}
      alt="Freddy UI Logo"
      width={35}
      height={35}
      style={{
        width: "auto",
        height: "auto",
      }}
      className={cn("h-6 w-auto object-contain", className)}
    />
  );
};

"use client";
import type React from "react";
import { cn } from "@/lib/utils";

type MenuToggleProps = React.ComponentProps<"svg"> & {
  open: boolean;
  duration?: number;
};

export function MenuToggleIcon({
  open,
  className,
  fill = "none",
  stroke = "currentColor",
  strokeWidth = 2.5,
  strokeLinecap = "round",
  strokeLinejoin = "round",
  duration = 500,
  ...props
}: MenuToggleProps) {
  return (
    <svg
      className={cn(
        "transition-transform ease-in-out",
        open && "-rotate-45",
        className
      )}
      fill={fill}
      stroke={stroke}
      strokeLinecap={strokeLinecap}
      strokeLinejoin={strokeLinejoin}
      strokeWidth={strokeWidth}
      style={{
        transitionDuration: `${duration}ms`,
      }}
      viewBox="0 0 32 32"
      {...props}
    >
      <path
        className={cn(
          "transition-all ease-in-out",
          open
            ? "[stroke-dasharray:20_300] [stroke-dashoffset:-32.42px]"
            : "[stroke-dasharray:12_63]"
        )}
        d="M27 10 13 10C10.8 10 9 8.2 9 6 9 3.5 10.8 2 13 2 15.2 2 17 3.8 17 6L17 26C17 28.2 18.8 30 21 30 23.2 30 25 28.2 25 26 25 23.8 23.2 22 21 22L7 22"
        style={{
          transitionDuration: `${duration}ms`,
        }}
      />
      <path d="M7 16 27 16" />
    </svg>
  );
}

"use client";
import React from "react";

export function useScroll(threshold: number) {
  const [scrolled, setScrolled] = React.useState(false);

  const onScroll = React.useCallback(() => {
    setScrolled(window.scrollY > threshold);
  }, [threshold]);

  React.useEffect(() => {
    window.addEventListener("scroll", onScroll);
    return () => window.removeEventListener("scroll", onScroll);
  }, [onScroll]);

  // also check on first load
  React.useEffect(() => {
    onScroll();
  }, [onScroll]);

  return scrolled;
}
